svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
var svg   = document.getElementById('root');
  var caEl  = document.querySelector('.data-layer');

  /* §2 — isDark hoisted before all build/animation code */

  /* §3 A1 canonical — inline style.animation per series with computed stagger.
     animationend clears style.animation and adds .visible;
     .sg.visible { opacity:1 } owns the stable state. No class removal needed.
     Stagger: min(0.25, 1.0/6)=0.167s. Last delay: 0.835s. */
  var sgs       = Array.prototype.slice.call(document.querySelectorAll('.sg'));
  var count     = sgs.length;
  var stagger   = Math.min(0.25, 1.0 / count);
  var lastDelay = (count - 1) * stagger;
  var readyDelay = (lastDelay + 0.8 + 0.1) * 1000;

  sgs.forEach(function(sg, i) {
    sg.style.animation = 'fadeIn 0.8s ease-out ' + (i * stagger).toFixed(3) + 's';
    sg.addEventListener('animationend', function handler() {
      sg.removeEventListener('animationend', handler);
      sg.style.animation = 'none';
      sg.classList.add('visible');
    }, { once: true });
  });

  setTimeout(function() { caEl.classList.add('ready'); }, readyDelay);

  /* §4 — Dot hover: container-level mouseleave (dot hit areas from different series
     share pixel positions — adjacent/overlapping targets need container removal).
     Stale-clear on every mouseenter — not optional. */
  var allDws = Array.prototype.slice.call(document.querySelectorAll('.dw'));
  var allSgs = Array.prototype.slice.call(document.querySelectorAll('.sg'));
  allDws.forEach(function(dw) {
    var sg = dw.closest('.sg');
    dw.addEventListener('mouseenter', function() {
      /* clear all stale active state before applying new */
      allDws.forEach(function(el) { el.classList.remove('active'); });
      allSgs.forEach(function(el) { el.classList.remove('active'); });
      if (caEl) caEl.classList.add('hovering');
      if (sg)   sg.classList.add('active');
      dw.classList.add('active');
    });
  });
  caEl.addEventListener('mouseleave', function() {
    allDws.forEach(function(el) { el.classList.remove('active'); });
    allSgs.forEach(function(el) { el.classList.remove('active'); });
    caEl.classList.remove('hovering');
  });

  /* ── Dark mode ── */
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
